"use client"

import { useState, useContext, useEffect } from "react"
import { Link } from "react-router-dom"
import { ProfileContext } from "../../context/profile/ProfileContext"
import { AlertContext } from "../../context/alert/AlertContext"

const DashboardActions = () => {
  const { profile, addPlatform } = useContext(ProfileContext)
  const { setAlert } = useContext(AlertContext)
  const [platforms, setPlatforms] = useState([])
  const [showAddPlatform, setShowAddPlatform] = useState(false)
  const [platformData, setPlatformData] = useState({
    name: "",
    username: "",
    url: "",
  })

  useEffect(() => {
    // Fetch available platforms
    const fetchPlatforms = async () => {
      try {
        const res = await fetch("/api/platforms")
        const data = await res.json()
        setPlatforms(data.data)
      } catch (err) {
        console.error("Error fetching platforms:", err)
      }
    }

    fetchPlatforms()
  }, [])

  const { name, username, url } = platformData

  const onChange = (e) => setPlatformData({ ...platformData, [e.target.name]: e.target.value })

  const onSubmit = async (e) => {
    e.preventDefault()

    if (!name || !username) {
      setAlert("Please provide both platform and username", "danger")
      return
    }

    const result = await addPlatform(platformData)

    if (result.success) {
      setAlert(result.msg, "success")
      setPlatformData({
        name: "",
        username: "",
        url: "",
      })
      setShowAddPlatform(false)
    } else {
      setAlert(result.msg, "danger")
    }
  }

  // Auto-fill URL based on platform and username
  useEffect(() => {
    if (name && username && platforms.length > 0) {
      const platform = platforms.find((p) => p.name === name)
      if (platform) {
        setPlatformData({
          ...platformData,
          url: `${platform.baseUrl}${username}`,
        })
      }
    }
  }, [name, username, platforms])

  return (
    <div className="bg-white p-4 rounded-lg shadow-md">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-xl font-semibold">Profile Actions</h2>
        <div className="flex gap-2">
          <Link to="/edit-profile" className="bg-blue-600 text-white px-3 py-1 rounded hover:bg-blue-700">
            Edit Profile
          </Link>
          <button
            onClick={() => setShowAddPlatform(!showAddPlatform)}
            className="bg-green-600 text-white px-3 py-1 rounded hover:bg-green-700"
          >
            {showAddPlatform ? "Cancel" : "Add Platform"}
          </button>
        </div>
      </div>

      {showAddPlatform && (
        <form onSubmit={onSubmit} className="border-t pt-4">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-gray-700 mb-1" htmlFor="name">
                Platform
              </label>
              <select
                id="name"
                name="name"
                value={name}
                onChange={onChange}
                className="w-full px-3 py-2 border rounded"
                required
              >
                <option value="">Select Platform</option>
                {platforms.map((platform) => (
                  <option key={platform.name} value={platform.name}>
                    {platform.name}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-gray-700 mb-1" htmlFor="username">
                Username
              </label>
              <input
                type="text"
                id="username"
                name="username"
                value={username}
                onChange={onChange}
                className="w-full px-3 py-2 border rounded"
                required
              />
            </div>

            <div>
              <label className="block text-gray-700 mb-1" htmlFor="url">
                URL (auto-generated)
              </label>
              <input
                type="text"
                id="url"
                name="url"
                value={url}
                onChange={onChange}
                className="w-full px-3 py-2 border rounded bg-gray-50"
                readOnly
              />
            </div>
          </div>

          <button type="submit" className="mt-4 bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700">
            Add Platform
          </button>
        </form>
      )}
    </div>
  )
}

export default DashboardActions
